function(inputs) {
  const rackCount = inputs.rackCount || 50;
  const targetKW = inputs.targetKW || 40;
  const totalDemandKW = rackCount * targetKW;
  const micMVA = inputs.micMVA || 5;
  const micUtilisation = inputs.micUtilisation || 0.85;
  const busSectionA = inputs.busSectionA || 1600;
  const busUtilisation = inputs.busUtilisation || 0.73;
  const voltage = inputs.voltage || 415;
  const pf = inputs.pf || 0.85;
  const sqrt3 = 1.732;

  const micHeadroomKVA = micMVA * 1000 * (1 - micUtilisation);
  const micHeadroomKW = micHeadroomKVA * pf;
  const busAvailableA = busSectionA * (1 - busUtilisation);
  const busHeadroomKW = (busAvailableA * voltage * sqrt3 * pf) / 1000;

  const micPass = micHeadroomKW >= totalDemandKW;
  const busPass = busHeadroomKW >= totalDemandKW;

  if (!micPass && !busPass) {
    return { pass: false, reason: 'Both MIC headroom (' + Math.round(micHeadroomKW) + ' kW) and bus section headroom (' + Math.round(busHeadroomKW) + ' kW) are insufficient for ' + totalDemandKW + ' kW demand. MIC upgrade and bus section replacement both required.' };
  } else if (!micPass) {
    return { pass: false, reason: 'MIC headroom (' + Math.round(micHeadroomKW) + ' kW) insufficient for ' + totalDemandKW + ' kW demand. Grid connection upgrade required (12–24 months via ESB Networks).' };
  } else if (!busPass) {
    return { pass: false, reason: 'Bus section headroom (' + Math.round(busHeadroomKW) + ' kW) insufficient for ' + totalDemandKW + ' kW demand. Bus section replacement required.' };
  }
  return { pass: true, reason: 'Both MIC (' + Math.round(micHeadroomKW) + ' kW headroom) and bus section (' + Math.round(busHeadroomKW) + ' kW headroom) can support ' + totalDemandKW + ' kW additional demand.' };
}

function(inputs) {
  const targetKW = inputs.targetKW || 15;
  const pduPhase = inputs.pduPhase || 1;
  const pduAmps = inputs.pduAmps || 32;
  const voltage = inputs.voltage || 230;
  const feeds = inputs.feeds || 2;
  const containmentInstalled = inputs.containmentInstalled || false;

  var maxPerFeed;
  if (pduPhase === 1) {
    maxPerFeed = (pduAmps * voltage) / 1000;
  } else {
    maxPerFeed = (pduAmps * voltage * 1.732) / 1000;
  }
  const totalPDUCapacity = maxPerFeed * feeds;
  const thermalOK = containmentInstalled;
  const powerOK = totalPDUCapacity >= targetKW;

  if (!thermalOK && !powerOK) {
    return { pass: false, reason: 'Neither thermal capacity (no containment) nor power capacity (' + totalPDUCapacity.toFixed(1) + ' kW PDU max vs ' + targetKW + ' kW target) is sufficient.' };
  } else if (!thermalOK) {
    return { pass: false, reason: 'Containment not installed — thermal capacity insufficient for ' + targetKW + ' kW/rack even though PDU capacity (' + totalPDUCapacity.toFixed(1) + ' kW) is adequate.' };
  } else if (!powerOK) {
    return { pass: false, reason: 'Containment installed but PDU capacity (' + totalPDUCapacity.toFixed(1) + ' kW max) is below target ' + targetKW + ' kW/rack. PDU upgrade required.' };
  }
  return { pass: true, reason: 'Both containment (thermal) and PDU capacity (' + totalPDUCapacity.toFixed(1) + ' kW) support target density of ' + targetKW + ' kW/rack.' };
}

function(inputs) {
  var targetKW = inputs.targetKW || 35;
  var deltaT = inputs.deltaT || 20;
  var rho = 1.2;
  var cp = 1005;
  var baseFlow = 0.42;
  var baseFanPower = 0.3;
  var electricityPrice = inputs.electricityPrice || 0.12;
  var noiseLimit = 80;

  var requiredFlow = (targetKW * 1000) / (rho * cp * deltaT);
  var fanPower = baseFanPower * Math.pow(requiredFlow / baseFlow, 3);
  var rackPUE = (targetKW + fanPower) / targetKW;
  var annualFanCost = fanPower * 8760 * electricityPrice;
  var estimatedNoise = 70 + 10 * Math.log10(requiredFlow / 0.42);

  var issues = [];
  if (rackPUE > 1.3) issues.push('Rack-level PUE ' + rackPUE.toFixed(2) + ' exceeds EU Taxonomy 1.3 threshold');
  if (fanPower > targetKW * 0.3) issues.push('Fan power (' + fanPower.toFixed(1) + ' kW) exceeds 30% of IT load — economic crossover to liquid cooling');
  if (estimatedNoise > noiseLimit) issues.push('Estimated noise ' + estimatedNoise.toFixed(0) + ' dB(A) exceeds 80 dB(A) action level');

  if (issues.length > 0) {
    return { pass: false, reason: 'Air cooling at ' + targetKW + ' kW/rack fails ' + issues.length + ' checks: ' + issues.join('; ') + '. Annual fan energy cost: €' + Math.round(annualFanCost).toLocaleString() + '/rack.' };
  }
  return { pass: true, reason: 'Air cooling at ' + targetKW + ' kW/rack is within thermal, acoustic, and economic limits. Fan power: ' + fanPower.toFixed(1) + ' kW/rack. PUE: ' + rackPUE.toFixed(2) + '.' };
}

function(inputs) {
  var targetKW = inputs.targetKW || 40;
  var leaseYears = inputs.leaseYears || 10;
  var electricityPrice = inputs.electricityPrice || 0.12;
  var rackCount = inputs.rackCount || 50;
  var densityGrowthProb = inputs.densityGrowthProb || 0.5;
  var futureTargetKW = inputs.futureTargetKW || 60;
  var airCapex = inputs.airCapex || 1160000;
  var dlcCapex = inputs.dlcCapex || 1820000;

  var airCoolingKWperRack = targetKW > 25 ? targetKW * 0.45 : targetKW * 0.15;
  var dlcCoolingKWperRack = targetKW * 0.075;
  var airAnnualEnergy = rackCount * airCoolingKWperRack * 8760 * electricityPrice;
  var dlcAnnualEnergy = rackCount * dlcCoolingKWperRack * 8760 * electricityPrice;
  var annualSaving = airAnnualEnergy - dlcAnnualEnergy;
  var capexPremium = dlcCapex - airCapex;
  var simplePayback = capexPremium / annualSaving;
  var canAirServeFuture = futureTargetKW <= 41;

  var recommendation;
  if (simplePayback < 3 && !canAirServeFuture) {
    recommendation = 'DLC strongly recommended: ' + simplePayback.toFixed(1) + '-year payback on premium and air cannot serve future ' + futureTargetKW + ' kW density.';
  } else if (simplePayback < 5) {
    recommendation = 'DLC recommended: ' + simplePayback.toFixed(1) + '-year payback. Air carries stranded infrastructure risk.';
  } else {
    recommendation = 'Marginal — consider lease term and density growth probability carefully.';
  }

  return { pass: simplePayback < leaseYears * 0.5, reason: recommendation + ' Annual energy saving with DLC: €' + Math.round(annualSaving).toLocaleString() + '. Capex premium: €' + Math.round(capexPremium).toLocaleString() + '.' };
}

function(inputs) {
  var rackCount = inputs.rackCount || 50;
  var targetKW = inputs.targetKW || 100;
  var totalMW = (rackCount * targetKW) / 1000;
  var chilledWaterSpare = inputs.chilledWaterSpareMW || 1.5;
  var cduCapacityKW = inputs.cduCapacityKW || 500;
  var pipingDistanceM = inputs.pipingDistanceM || 20;
  var maxPipingM = 30;
  var opsExperience = inputs.opsLiquidExperience || false;

  var cdusRequired = Math.ceil((totalMW * 1000) / cduCapacityKW) + 1;
  var chilledWaterOK = chilledWaterSpare >= totalMW;
  var pipingOK = pipingDistanceM <= maxPipingM;

  var issues = [];
  if (!chilledWaterOK) issues.push('Chilled water spare capacity (' + chilledWaterSpare + ' MW) insufficient for ' + totalMW + ' MW heat rejection');
  if (!pipingOK) issues.push('Piping distance (' + pipingDistanceM + 'm) exceeds recommended 30m maximum');
  if (!opsExperience) issues.push('Operations team has no liquid cooling experience — training programme required before go-live');

  if (issues.length > 0) {
    return { pass: false, reason: cdusRequired + ' CDUs required (inc N+1). Issues: ' + issues.join('; ') };
  }
  return { pass: true, reason: cdusRequired + ' CDUs required (inc N+1). Chilled water, piping distance, and ops readiness all adequate.' };
}

function(inputs) {
  var rackCount = inputs.rackCount || 20;
  var rackPeakKW = 155;
  var rackWeightLbs = inputs.rackWeightLbs || 3200;
  var floorRatingPSF = inputs.floorRatingPSF || 150;
  var micMVA = inputs.micMVA || 5;
  var micUtilisation = inputs.micUtilisation || 0.85;
  var existingDLCCapacityMW = inputs.existingDLCCapacityMW || 5;
  var rackTDPKW = 135;

  var totalPeakMW = (rackCount * rackPeakKW) / 1000;
  var micHeadroomMW = (micMVA * (1 - micUtilisation) * 0.85);
  var rackPointLoadPSF = rackWeightLbs / (0.72 * 10.764);
  var totalHeatMW = (rackCount * rackTDPKW) / 1000;
  var dlcGapMW = totalHeatMW - (existingDLCCapacityMW > 0 ? 0 : 0);

  var issues = [];
  if (totalPeakMW > micHeadroomMW) issues.push('MIC upgrade required: need ' + totalPeakMW.toFixed(1) + ' MW, headroom ' + micHeadroomMW.toFixed(2) + ' MW');
  if (rackPointLoadPSF > floorRatingPSF) issues.push('Floor overloaded: ' + Math.round(rackPointLoadPSF) + ' psf vs ' + floorRatingPSF + ' psf rating — slab-to-slab mounting required');
  if (rackPeakKW > 142) issues.push('Peak power (' + rackPeakKW + ' kW) exceeds TDP — electrical must be sized for peak, not average');

  return { pass: issues.length === 0, reason: issues.length > 0 ? 'GB300 deployment blocked by ' + issues.length + ' constraints: ' + issues.join('; ') : 'All constraints cleared for ' + rackCount + ' GB300 racks.' };
}

function(inputs) {
  var rackCount = inputs.rackCount || 50;
  var rackKW = inputs.rackKW || 40;
  var existingBusA = inputs.existingBusA || 1600;
  var voltage = 415;
  var pf = 0.85;
  var sqrt3 = 1.732;
  var totalKW = rackCount * rackKW;
  var requiredA = (totalKW * 1000) / (voltage * sqrt3 * pf);
  var busOK = existingBusA >= requiredA;
  var perRackA = (rackKW * 1000) / (voltage * sqrt3 * pf);

  if (!busOK) {
    return { pass: false, reason: 'Bus section ' + existingBusA + 'A insufficient for ' + Math.round(requiredA) + 'A demand (' + totalKW + ' kW at 415V, 0.85 pf). New section rated ' + (Math.ceil(requiredA / 400) * 400) + 'A+ required. Per-rack feed: ' + Math.round(perRackA) + 'A — requires 3-phase MCCB and cable sizing per IS 10101 §523.' };
  }
  return { pass: true, reason: 'Bus section ' + existingBusA + 'A adequate for ' + Math.round(requiredA) + 'A demand. Per-rack feed: ' + Math.round(perRackA) + 'A.' };
}

function(inputs) {
  var voltageAC = inputs.voltageAC || 415;
  var rackKW = inputs.rackKW || 135;
  var cableRunM = inputs.cableRunM || 20;
  var rackCount = inputs.rackCount || 50;
  var leaseYears = inputs.leaseYears || 12;
  var electricityPrice = inputs.electricityPrice || 0.12;
  var pf = 0.85;
  var sqrt3 = 1.732;

  var currentA = (rackKW * 1000) / (voltageAC * sqrt3 * pf);
  var cableArea = currentA > 200 ? 120 : currentA > 150 ? 95 : 70;
  var resistivity = 1000 / (56 * cableArea);
  var irLossPerRack = Math.pow(currentA, 2) * resistivity * cableRunM * 3 / 1000;
  var totalIRLoss = irLossPerRack * rackCount;
  var annualCost = totalIRLoss * 8760 * electricityPrice;
  var lifecycleCost = annualCost * leaseYears;

  return { pass: true, reason: 'At ' + voltageAC + 'V: ' + Math.round(currentA) + 'A/rack, cable ' + cableArea + 'mm², I²R loss ' + irLossPerRack.toFixed(1) + ' kW/rack, total ' + totalIRLoss.toFixed(0) + ' kW, annual cost €' + Math.round(annualCost).toLocaleString() + ', lifecycle ('+leaseYears+'yr) €' + Math.round(lifecycleCost).toLocaleString() + '.' };
}

function(inputs) {
  var scenarios = [
    { name: '40 kW / 50 racks', capex: 5900000, annualRevenue: 2000000, rackKW: 40, racks: 50 },
    { name: '100 kW / 50 racks', capex: 8000000, annualRevenue: 4400000, rackKW: 100, racks: 50 },
    { name: '135 kW / 20 racks', capex: 6800000, annualRevenue: 4300000, rackKW: 135, racks: 20 }
  ];
  var fillRate = inputs.fillRate || 0.8;
  var discountRate = inputs.discountRate || 0.07;
  var leaseYears = inputs.leaseYears || 12;

  var results = scenarios.map(function(s) {
    var annualCF = s.annualRevenue * fillRate;
    var pvFactor = (1 - Math.pow(1 + discountRate, -leaseYears)) / discountRate;
    var npv = (annualCF * pvFactor) - s.capex;
    var breakeven = s.capex / (s.annualRevenue * pvFactor);
    return s.name + ': NPV €' + Math.round(npv/1000) + 'K at ' + (fillRate*100) + '% fill, breakeven ' + (breakeven*100).toFixed(0) + '% fill';
  });

  return { pass: true, reason: results.join(' | ') };
}
